10: const Diacritic = enum(u8) {
11:     empty, // nguyên âm, không dấu.
12:     circumflex, // dấu nón: â, ô, ê.
13:     horn, // dấu móc: ư, ơ.
14:     breve, // dấu ă.
15:     stroke, // dấu gạch: đ.
16: };
17: 
18: const Tone = enum(u8) {
19:     level, // thanh ngang, không dấu.
20:     rising, // sắc.
21:     falling, // huyền.
22:     dipping_rising, // hỏi.
23:     rising_glottalized, // ngã.
24:     falling_glottalized, // nặng.
25: };
